var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최고 관리자 권한 확인. 함선 동결을 해제합니다.</color>","JPN":"<color=#ffd34c>最高管理者権限確認。艦船の凍結を解除します。</color>","ENG":"<color=#ffd34c>Supreme Administrator authorization confirmed. Removing cryostasis.</color>","TWN":"<color=#ffd34c>確認最高管理者權限，解除艦船凍結。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_TECH_12"},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떤가, 내 실력이? 이거 정말 기술자로 전직해도 되겠군.","JPN":"見たか？　本気でエンジニアへの転職を考えるべきかもな。","ENG":"So what do you think of that? Maybe I could really be an engineer for a living.","TWN":"怎麼樣，我的實力？我這樣可以轉職成真正的技術人員吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"평범하게 관리자 권한으로 해제하셨으면서 말씀은 잘하시는군요.","JPN":"普通に管理者権限で解除しておきながら、\\nその自画自賛ぶりはさすがですね。","ENG":"Oh, please. All you did was use your Administrator authority to access the system.","TWN":"您只是很普通地用管理者權限解除凍結而已，還這麼敢說啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"누가 들으면 해킹이라도 한 줄 알겠습니다.","JPN":"誰かが聞いていれば、本当にハッキングでもしたのかと思われそうです。","ENG":"It's not like you actually did any hacking.","TWN":"別人聽了，還以為你是駭客呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가끔은 칭찬이라도 해 주지 그러나. 우리 부사장은 너무 딱딱해서 문제야.","JPN":"たまには褒めてくれたっていいだろ。\\nわが社の副社長はそう堅苦しいからいけないんだ。","ENG":"You could really work on complimenting people. You're too stiff for your own good, Vice President.","TWN":"偶爾也稱讚我一下嘛，我們副總的問題就是太死板了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"말이 나와서 말인데, 우리 회사 직원들은 다들 한 성질 해서 말이지......","JPN":"ついでに言えば、わが社の社員は揃いも揃って\\nジョークの通じない怒りん坊だらけで……","ENG":"Speaking of which, all our employees seem to have quite the temper...","TWN":"說到這個，我們公司的員工都很有個性呢……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이번 일이 잘 끝나면 한 번 고려해 보기로 하죠.","JPN":"その話はこの件が片付いた後でじっくり聞かせていただきます。","ENG":"I'll consider it once we make it out of here alive.","TWN":"如果這次的事情順利解決，我會考慮一下的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그보다, 주변이 갑자기 조용해진 것 같네요.","JPN":"それより、周りが急に静かになりましたね。","ENG":"By the way, it seems awfully quiet all of a sudden.","TWN":"話說回來，周圍好像突然變得安靜了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"예상대로군.","JPN":"予想通りだな。","ENG":"Yeah, I totally saw this coming.","TWN":"果然跟預料中的一樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......네, 예상대로군요.","JPN":"……はい、予想通りです。","ENG":"Indeed.","TWN":"……是啊，跟預料中的一樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"드디어......","JPN":"ようやく……","ENG":"Finally...","TWN":"終於……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"드디어 안에 들어갈 수 있게 됐어......!","JPN":"ようやく内部に踏み込めるのだな……！","ENG":"I can finally enter the ship!","TWN":"終於能進入內部了……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 약속대로 방주선의 동결은 해제했네.","JPN":"ああ。約束通り箱舟の凍結は解除してある。","ENG":"Indeed. As promised, I've undone the stasis of the Ark.","TWN":"是的，按照約定，我把方舟的凍結解除了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"훌륭하군!","JPN":"見事な働きだ！","ENG":"Excellent!","TWN":"太了不起了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"자, 비켜라. 안으로 들어가 봐야겠어.","JPN":"さあ、どけ。さっそく中に入らせてもらう。","ENG":"Now step aside! I've got to get in there.","TWN":"快，讓開，我要進去看看。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아. 그 전에 잠시만 기다려 주게.","JPN":"あっ、少し待ってくれ。その前に……","ENG":"Oh, by the way. Why don't you hang on for just a sec.","TWN":"喔，不過在那之前，妳得先等一下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"사사건건 걸리적거리는군! 기다릴 시간 따윈 없다!","JPN":"いちいち癇に障る奴め！　待つ暇などない！","ENG":"Why do you have to keep getting in the way?! I don't have time to wait!","TWN":"你真是每件事都要妨礙我耶！我沒有時間等了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 기다려 줘야겠어.","JPN":"いいえ、待ってもらうわ。","ENG":"No, I'm afraid you must.","TWN":"不，你必須等一下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이수연?","JPN":"カナミ？","ENG":"Sooyeon?","TWN":"李秀妍？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"방주의 동결을 풀자마자 싸움이 멈추던데, 어째서지?","JPN":"箱舟の凍結を解いたとたん戦いが止まったわ。\\nそれはどうして？","ENG":"The fighting stopped as soon as the stasis was lifted. How come?","TWN":"為什麼解除方舟的凍結後，戰鬥就立刻停止了？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"동료들과 회포를 풀라고 적들이 휴전이라도 해 주던가?","JPN":"仲間との再会を喜び合えるように、\\n敵が休戦を申し出てくれたのかしら？","ENG":"Did the enemies agree to a ceasefire so you can catch up with your old pals?","TWN":"是為了慶祝妳和同伴重逢，所以敵人宣佈休戰了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"큭...... 크큭......","JPN":"クッ……ククッ……","ENG":"Hah... Hah hah...","TWN":"呵……呵呵……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"하하하! 아하하하하!!","JPN":"ハハハッ！　アッハハハハッ！！","ENG":"Hah hah! Ah hah hah hah hah!","TWN":"哈哈哈！啊哈哈哈哈哈！！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"아, 그래. 너무 기쁜 나머지 소개를 깜박했군.","JPN":"ああ、そうだったな。喜びのあまり言い忘れていたか。","ENG":"Right, of course. I was so excited that I forgot to make my introductions.","TWN":"啊，對了。我太高興了，都忘記向你們介紹了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이쪽은 내 부관인 알렉스다.","JPN":"紹介しよう。こちらは私の副官、アレックスだ。","ENG":"This here is my faithful adjutant, Alex.","TWN":"這是我的副官，雅蕾克絲。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"밖에 있던 녀석들도 나의 충성스러운 병사들이지.","JPN":"外にいた連中も皆、私の忠実な兵士たちだ。","ENG":"And the lot outside our my loyal troops.","TWN":"外面的傢伙們也都是我忠誠的士兵。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그리고 동시에, 나와 마찬가지로 여기서 태어난 그림자이고.","JPN":"そして私同様、ここで生まれたシャドウでもある。","ENG":"And just like them, I was born here, as a Shadow.","TWN":"而且也是同時和我一起在這裡誕生的暗影。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"나와 이 녀석들이 싸운 건 너희를 속이기 위한 연출이었을 뿐이다.","JPN":"私とこいつらが戦ったのは貴様たちを騙すための芝居……\\nただの演出だ。","ENG":"I fought them only to deceive you two.","TWN":"我會和他們戰鬥，是為了騙過你們所演出的戲碼。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"흐음. 대장이 현실세계로 올라가겠다고 했을 때는 드디어 미친 줄 알았는데......","JPN":"ふ～ん。隊長ちゃんが現実世界に浮上すると言ったときは、\\nいよいよ気が触れたのかと思ったけど……","ENG":"Hmm... I thought you had finally lost it when you said you'd go to the Normalside...","TWN":"嗯，我聽隊長說要去躍出現實世界後，還以為你真的瘋了……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"정말 동결을 풀 수 있는 인간을 데려왔네. 조금 놀랐어.","JPN":"本当に凍結を解ける人間を連れてきたじゃない。驚いちゃったわ。","ENG":"Never figured you'd actually bring someone who can remove the stasis. Honestly, I'm impressed.","TWN":"卻沒想到隊長真的把能解除凍結的人帶過來了，這讓我真有些驚訝。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"아, 그렇다고 너무 겁먹진 마라. 난 자비로운 편이거든.","JPN":"ああ、そう怯えることはないぞ。私は慈悲深いからな。","ENG":"Oh, don't be too frightened. I'm fairly merciful, you see.","TWN":"啊，你們不需要害怕，因為我是個慈悲的人。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"동결을 해제해 준 공로를 높이 사서, 고통 없이 죽여 주지.","JPN":"凍結解除の功績に免じて、苦しませずに殺してやる。","ENG":"To commend you for your efforts in removing the stasis, I'll make it quick and painless for you.","TWN":"看在你們解除凍結的份上，我殺你們的時候不會讓妳們感受到痛苦的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"말이 안 나올 만큼 놀랐나, 이수연?","JPN":"絶句するほど驚いたか？　カナミ・キズナ。","ENG":"Cat got your tongue, Sooyeon?","TWN":"是不是嚇得連話都說不出來了，李秀妍？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"하긴, 옛 동료의 모습에 속아 넘어갔으니 충격 받을 만도 하지.","JPN":"かつての仲間の姿にころっと騙されたのだから、さぞやショックだったろう。","ENG":"I suppose seeing your old colleague betray you must be pretty shocking.","TWN":"也是，被昔日好友的模樣所欺騙，一定受到很大的打擊吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 놀랄 수 없어서 죄송하네요.","JPN":"いいえ。驚いてあげられなくてごめんなさいね。","ENG":"No. Sorry I'm not shocked at all.","TWN":"不，很抱歉我沒有被嚇到。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신이 진짜 류드밀라가 아니라는 건 처음부터 알고 있었으니까요.","JPN":"あなたが本物のリュドミラでないことは\\n始めからわかっていましたので。","ENG":"I knew all along that you're not the real Lyudmila.","TWN":"我從一開始就知道妳不是盧德米拉。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};